S Counter { counts: {s: i32} }

I Counter {
    +f new() -> Counter { @Counter { counts: {} } }
    +f add(&!self, key: s) {
        v current: i32 = self.counts.get(&key).unwrap_or(0);
        self.counts.insert(key, current + 1);
    }
    +f get(&self, key: &s) -> i32 { self.counts.get(key).unwrap_or(0) }
}

rust_equivalent.rs_source:
use std::collections::HashMap;

struct Counter { counts: HashMap<String, i32> }

impl Counter {
    pub fn new() -> Counter { Counter { counts: HashMap::new() } }
    pub fn add(&mut self, key: String) {
        let current = self.counts.get(&key).copied().unwrap_or(0);
        self.counts.insert(key, current + 1);
    }
    pub fn get(&self, key: &str) -> i32 { *self.counts.get(key).unwrap_or(&0) }
}

