+f merge(a: [i32]~, b: [i32]~) -> [i32]~ {
    m result: [i32]~ = [];
    m i: usize = 0;
    m j: usize = 0;
    loop {
        ? i >= a.len() && j >= b.len() { break; }
        ? i >= a.len() { result.push(b[j]); j = j + 1; }
        : { ? j >= b.len() { result.push(a[i]); i = i + 1; }
        : { ? a[i] <= b[j] { result.push(a[i]); i = i + 1; }
        : { result.push(b[j]); j = j + 1; } } }
    }
    result
}

rust_equivalent.rs_source:
pub fn merge(a: Vec<i32>, b: Vec<i32>) -> Vec<i32> {
    let mut result = Vec::new();
    let (mut i, mut j) = (0, 0);
    loop {
        if i >= a.len() && j >= b.len() { break; }
        if i >= a.len() { result.push(b[j]); j += 1; }
        else if j >= b.len() { result.push(a[i]); i += 1; }
        else if a[i] <= b[j] { result.push(a[i]); i += 1; }
        else { result.push(b[j]); j += 1; }
    }
    result
}

