+f reverse(items: &![i32]~) {
    m i: usize = 0;
    m j: usize = items.len() - 1;
    loop {
        ? i >= j { break; }
        items.swap(i, j);
        i = i + 1;
        j = j - 1;
    }
}

rust_equivalent.rs_source:
pub fn reverse(items: &mut Vec<i32>) {
    let (mut i, mut j) = (0, items.len() - 1);
    loop {
        if i >= j { break; }
        items.swap(i, j);
        i += 1;
        j -= 1;
    }
}

