S CircBuf {
    data: [i32]~,
    head: usize,
    count: usize,
    cap: usize,
}

I CircBuf {
    +f new(cap: usize) -> CircBuf {
        @CircBuf { data: [], head: 0, count: 0, cap: cap }
    }
    +f push(&!self, val: i32) {
        v idx: usize = (self.head + self.count) % self.cap;
        ? self.count < self.cap {
            self.data.push(val);
            self.count = self.count + 1;
        } : {
            self.data[idx] = val;
            self.head = (self.head + 1) % self.cap;
        }
    }
    +f peek(&self) -> ?i32 {
        ? self.count == 0 { ?None } : { ?Some(self.data[self.head]) }
    }
}

rust_equivalent.rs_source:
struct CircBuf {
    data: Vec<i32>,
    head: usize,
    count: usize,
    cap: usize,
}

impl CircBuf {
    pub fn new(cap: usize) -> CircBuf {
        CircBuf { data: Vec::new(), head: 0, count: 0, cap }
    }
    pub fn push(&mut self, val: i32) {
        let idx = (self.head + self.count) % self.cap;
        if self.count < self.cap {
            self.data.push(val);
            self.count += 1;
        } else {
            self.data[idx] = val;
            self.head = (self.head + 1) % self.cap;
        }
    }
    pub fn peek(&self) -> Option<i32> {
        if self.count == 0 { None } else { Some(self.data[self.head]) }
    }
}
